#include <stdio.h>
#include <unistd.h>
#include <string.h>
int main(void) {
    int fd[2];
    pipe(fd);
    const char *msg = "hello pipe";
    write(fd[1], msg, strlen(msg));
    close(fd[1]);
    char buf[32];
    ssize_t n = read(fd[0], buf, sizeof(buf) - 1);
    buf[n] = '\0';
    printf("Received: %s\n", buf);
    close(fd[0]);
    return 0;
}

