#include <stdio.h>
#include <unistd.h>
#include <string.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    int fd[2];
    pipe(fd);                              // ★ fd[0]=lecture fd[1]=écriture
    const char *msg = "hello pipe";
    write(fd[1], msg, strlen(msg));        // ★ écrire dans l'extrémité écriture
    close(fd[1]);                          // ★ signaler EOF
    char buf[32];
    ssize_t n = read(fd[0], buf, sizeof(buf) - 1); // ★ lire depuis l'extrémité lecture
    buf[n] = '\0';
    printf("Received: %s\n", buf);
    close(fd[0]);
    return 0;
}

